import{_ as a,c as e,o as t,V as r}from"./chunks/framework.9b555ede.js";const i="/images/dataScreen1.png",l="/images/dataScreen2.png",f=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"original/【开发】kidar-echarts.md","filePath":"original/【开发】kidar-echarts.md","lastUpdated":1640536454000}'),o={name:"original/【开发】kidar-echarts.md"},s=r('<h1 align="center">kidar-echarts 🍥 更简单的Echarts</h1><p align="center"> 将必要有关联的配置属性进行封装，仅暴露用户可能自定义的配置选项，无需关注自适应、鼠标点击事件等操作，支持自定义插件，更好的复用配置 </p><p align="center"> 具体可点击查看在线文档 ✨ <a href="https://kidarjs.github.io/kidar-echarts">Live Doc</a></p><h3 id="为什么选择kidarecharts" tabindex="-1">为什么选择KidarEcharts <a class="header-anchor" href="#为什么选择kidarecharts" aria-label="Permalink to &quot;为什么选择KidarEcharts&quot;">​</a></h3><p>随着数字化不断普及，数据量大爆发，很多企业都开始开发各种数据统计平台。</p><p>在使用大量echarts绘制不同图表的业务中，项目中花样繁多的option配置重复性很高，由于涉及到的配置项过多，编写顺序随意，很难将类似的图表进行整合，尽管项目也封装了一些通用配置echarts，但还是无法避免多人协作过程中的混用</p><p>编写冗长繁杂的option很痛苦，属性多得记不住，总是需要查看文档来进行配置</p><p>对于复杂一点的图表，option配置项多且冷门，网络上存在的echarts图表都是以demo的形式展现，且使用原生的echarts编码方式，难以阅读，开发人员很难学习使用</p><p>因此更贴合 Vue|React 使用者习惯的 KidarEcharts 组件，将会给你带来更舒适的开发体验，减少了echarts的学习成本。</p><p>KidarEcharts为了解决这个问题，将大家常用的option进行收集封装，通过懒加载的方式展现，减少echarts配置的学习成本。 并且支持自定义option文件，并通过安装插件的方式导入，方便复用。同时你也可以寻找社区分享的好用的option进行安装使用，我们仅需要关注图表所需数据格式、维度，就能画出漂亮的图表了。</p><h3 id="now" tabindex="-1">Now <a class="header-anchor" href="#now" aria-label="Permalink to &quot;Now&quot;">​</a></h3><p>目前组件还再完善中，也欢迎大家点评，如果你觉得这个组件还不错，也欢迎贡献代码，扩充更多好看的plugin <a href="https://www.makeapie.com/explore.html" target="_blank" rel="noreferrer">makeapie</a>,这个网站画的还不错，陆陆续续会集成过来</p><h3 id="🔥-features" tabindex="-1">🔥 Features <a class="header-anchor" href="#🔥-features" aria-label="Permalink to &quot;🔥 Features&quot;">​</a></h3><p>每个组件实例都是一个echarts，切换不同的echarts采用懒加载技术，更快更简单的实现不同图形的展示</p><ul><li>[x] 快速绘制出简单图形，饼图、折线、柱状、环形、多样组合、地图</li><li>[x] 支持自定义插件</li><li>[x] 支持自适应宽高，当容器大小变化时自动适应</li><li>[x] 支持Typescript</li><li>[ ] 支持自定义参数，方便定制tooltip、label等</li><li>[ ] 支持点击事件、鼠标移入移出事件</li><li>[ ] 支持3D</li></ul><h3 id="效果图预览" tabindex="-1">效果图预览 <a class="header-anchor" href="#效果图预览" aria-label="Permalink to &quot;效果图预览&quot;">​</a></h3><p><img src="'+i+'" alt="大屏1"><img src="'+l+'" alt="大屏2"></p><h3 id="涉及的技术" tabindex="-1">涉及的技术 <a class="header-anchor" href="#涉及的技术" aria-label="Permalink to &quot;涉及的技术&quot;">​</a></h3><ul><li>vite</li><li>vue-demi (使组件同时支持vue2、vue3)</li><li>react</li><li>typescript</li><li>echarts</li><li>echarts-gl</li></ul>',19),c=[s];function h(n,p,d,_,u,m){return t(),e("div",null,c)}const g=a(o,[["render",h]]);export{f as __pageData,g as default};
